import{_ as o,o as t,c as a,a2 as i}from"./chunks/framework.Bix3-HpO.js";const p=JSON.parse('{"title":"Plugin Blocks","description":"AkuraiGeo Plugin Blocks","frontmatter":{"title":"Plugin Blocks","description":"AkuraiGeo Plugin Blocks","weight":30,"extra":{"order":30},"head":[["link",{"rel":"canonical","href":"https://docs.dinomatic.com/docs/akurai-geo/blocks"}],["meta",{"property":"og:url","content":"https://docs.dinomatic.com/docs/akurai-geo/blocks"}],["meta",{"property":"og:title","content":"Plugin Blocks"}],["meta",{"property":"og:description","content":"AkuraiGeo Plugin Blocks"}],["meta",{"name":"twitter:title","content":"Plugin Blocks"}],["meta",{"name":"twitter:description","content":"AkuraiGeo Plugin Blocks"}]]},"headers":[],"relativePath":"docs/akurai-geo/blocks.md","filePath":"docs/akurai-geo/blocks.md"}'),s={name:"docs/akurai-geo/blocks.md"};function l(n,e,c,r,g,d){return t(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="plugin-blocks" tabindex="-1">Plugin Blocks <a class="header-anchor" href="#plugin-blocks" aria-label="Permalink to &quot;Plugin Blocks&quot;">​</a></h1><p>There are several blocks you can use to display your geo location based content on your website. Check them out below.</p><hr><h2 id="using-blocks" tabindex="-1">Using Blocks <a class="header-anchor" href="#using-blocks" aria-label="Permalink to &quot;Using Blocks&quot;">​</a></h2><p><img src="https://media.dinomatic.com/images/docs/akurai-geo/akurai-geo-blocks.png" alt="AkuraiGeo Blocks"></p><p>Below are the blocks available in AkuraiGeo plugin:</p><ul><li>Geo Listing</li><li>Geo Content</li><li>Review Geo Message</li></ul><hr><h3 id="geo-listing-block" tabindex="-1">Geo Listing Block <a class="header-anchor" href="#geo-listing-block" aria-label="Permalink to &quot;Geo Listing Block&quot;">​</a></h3><p>To add a new listing simply click on the + (Add block) sign and select Geo Listing in Akurai Blocks section.</p><p><img src="https://media.dinomatic.com/images/docs/akurai-geo/akurai-geo-blocks--geo-listing.png" alt="AkuraiGeo Blocks - Geo Listing"></p><p>In the content editor a new listing edit section will appear. On the 1st tab you select the listing options such as listing type (grid, table, etc.), terms and whether to display filters or not.</p><p>The 2nd tab, called Default, is where you select all reviews that you want to display to users from countries that are not in your list of targeted ones.</p><p>After that there&#39;s a new tab for each country you target, simply add reviews or leave them empty to display the Default selection.</p><p><img src="https://media.dinomatic.com/images/docs/akurai-geo/akurai-geo-blocks--geo-listing-manual.png" alt="AkuraiGeo Blocks - Geo Listing"></p><p><code>💁 since version 1.1.0</code> you can choose reviews manually or filter them by category and/or by tag. You can select a review tag and all reviews with that tag will be displayed. You can also set a limit, for example, display just 6 reviews tagged as &quot;usa&quot;.</p><p><img src="https://media.dinomatic.com/images/docs/akurai-geo/akurai-geo-blocks--geo-listing-tax.png" alt="AkuraiGeo Blocks - Geo Listing"></p><h3 id="geo-content-block" tabindex="-1">Geo Content Block <a class="header-anchor" href="#geo-content-block" aria-label="Permalink to &quot;Geo Content Block&quot;">​</a></h3><p>To add a new content block simply click on the + (Add block) sign and select Geo Content in Akurai Blocks section.</p><p><img src="https://media.dinomatic.com/images/docs/akurai-geo/akurai-geo-blocks--geo-content.png" alt="AkuraiGeo Blocks - Geo Content"></p><p>In the content editor a new Content Block edit section will appear. Add your content to the rich-text editor and simply select the countries by toggling them on or off.</p><h3 id="review-geo-message-block" tabindex="-1">Review Geo Message Block <a class="header-anchor" href="#review-geo-message-block" aria-label="Permalink to &quot;Review Geo Message Block&quot;">​</a></h3><p>To add a new message block simply click on the + (Add block) sign and select Review Geo Message in Akurai Blocks section.</p><p><img src="https://media.dinomatic.com/images/docs/akurai-geo/akurai-geo-blocks--review-geo-message.png" alt="AkuraiGeo Blocks - Review Geo Message"></p><p>In the content editor a new message block edit section will appear. You can overwrite the default texts for messages for whether visitor&#39;s country is or isn&#39;t supported or keep the defaults.</p><p>Next you can select a style from the &quot;Block Style&quot; dropdown: 2 options with just message and country flag (flag being either on left or right side) and 2 options with the message, the flag as well as a bonus text and affiliate link (only for cases where country is supported).</p><p>There is one more style called &quot;No Styles&quot; which will just print out the markup, and you can design your own message block by applying your CSS rules to it.</p>',27)])])}const k=o(s,[["render",l]]);export{p as __pageData,k as default};
